const x = $input.first().json;

let raw = String(x.user_text || '')
  .replace(/\u00a0/g, ' ')
  .replace(/\uFF0E/g, '.')
  .replace(/[\u2010\u2011\u2012\u2013\u2014\u2212\uFE58\uFE63\uFF0D]/g, '-')
  .replace(/,([^\s\d])/gi, ', $1')
  .replace(/,(\d)/g, ', $1');
const t =
  ' ' +
  raw
    .toLowerCase()
    .replace(/ё/g, 'е')
    .replace(/\s+/g, ' ')
    .trim() +
  ' ';

function num(v) {
  const n = Number(String(v).replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

/** После числа в сумме не должно идти площадь */
function looksLikeAreaAfterPrice(text, endIdx) {
  const tail = text.slice(endIdx, endIdx + 22);
  return /^\s*[,и]?\s*(м(²|\^2|\b)|кв|метр|квадрат)/i.test(tail);
}


function looksLikeAreaRangeAfterFrom(text, endIdx) {
  const tail = text.slice(endIdx, endIdx + 55);
  if (!/^\s+до\s+\d{1,3}(?:[.,]\d{1,2})?/i.test(tail)) return false;
  const afterDo = tail.replace(/^\s+до\s+\d{1,3}(?:[.,]\d{1,2})?/i, '');
  return /^\s+(?:кв|м(?:²|2)|м\.|квадрат)/i.test(afterDo);
}

function normalizeMoneyMatch(m, text) {
  const endIdx = m.index + m[0].length;
  if (looksLikeAreaAfterPrice(text, endIdx)) return null;
  if (looksLikeAreaRangeAfterFrom(text, endIdx)) return null;
  let val = Number(m[1].replace(/[\s]/g, '').replace(',', '.'));
  if (!Number.isFinite(val)) return null;
  const unit = (m[2] || '').toLowerCase();
  if (/млн|миллион/.test(unit)) val = Math.round(val * 1_000_000);
  else if (/тыс|тысяч/.test(unit)) val = Math.round(val * 1_000);
  else if (unit === 'к') val = Math.round(val * 1_000);
  else if (/р|руб|₽/.test(unit)) val = Math.round(val);
  else {
    if (val >= 1_000) val = Math.round(val);
    else val = Math.round(val * 1_000_000);
  }
  return val;
}

function parsePriceMax(text) {
  const res = [
    /\sдо\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
    /\sне\s+дороже\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
    /\sбюджет\s+до\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
    /\sмакс(?:имум)?\.?\s*(?:цена\s*)?([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
  ];
  let best = null;
  for (const re of res) {
    for (const m of text.matchAll(re)) {
      const v = normalizeMoneyMatch(m, text);
      if (v != null) best = v;
    }
  }
  return best;
}

function parsePriceMin(text) {
  const res = [
    /\sот\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
    /\sне\s+дешевле\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
    /\sминимум\s+([\d\s.,]+)\s*(млн|миллион|тыс|тысяч|к(?![а-яё])|р(?![а-яё])|руб|₽)?/gi,
  ];
  let best = null;
  for (const re of res) {
    for (const m of text.matchAll(re)) {
      const v = normalizeMoneyMatch(m, text);
      if (v != null) best = v;
    }
  }
  return best;
}

function pick(re) {
  const m = t.match(re);
  return m ? num(m[1]) : null;
}

const AREA_TAIL =
  '(?:м(?:²|\\^2)|кв\\.?\\s*м|м2|м\\.?\\s*кв|квадрат(?:ов|а|ные|ных)?(?:\\s*метр(?:ов|а)?)?)';

let min_area = null;
let max_area = null;
let areaApprox = false;


const areaPl = t.match(
  new RegExp(
    `\\sплощад(?:ь|и|ью|ей)\\s+от\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)\\s+до\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)(?:\\s+${AREA_TAIL})?(?=\\s|[,.]|$)`,
    'i'
  )
);
const areaRange1 = t.match(
  new RegExp(
    `\\sот\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)\\s+до\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)\\s+${AREA_TAIL}`,
    'i'
  )
);
const areaRange2 = t.match(
  /\s(\d{1,3}(?:[.,]\d{1,2})?)\s*[-–]\s*(\d{1,3}(?:[.,]\d{1,2})?)\s*(?:м(?:²|\^2)|кв\.?\s*м|м2|квадрат)/i
);

if (areaPl) {
  min_area = num(areaPl[1]);
  max_area = num(areaPl[2]);
} else if (areaRange1) {
  min_area = num(areaRange1[1]);
  max_area = num(areaRange1[2]);
} else if (areaRange2) {
  min_area = num(areaRange2[1]);
  max_area = num(areaRange2[2]);
}

function addMinArea(v) {
  if (v == null) return;
  min_area = min_area == null ? v : Math.max(min_area, v);
}
function addMaxArea(v) {
  if (v == null) return;
  max_area = max_area == null ? v : Math.min(max_area, v);
}

if (min_area == null && max_area == null) {
  addMinArea(pick(/\sот\s+(\d{1,3}(?:[.,]\d{1,2})?)\s+квадрат/i));
  addMaxArea(pick(/\sдо\s+(\d{1,3}(?:[.,]\d{1,2})?)\s+квадрат/i));
  addMinArea(pick(/\sне\s+менее\s+(\d{1,3}(?:[.,]\d{1,2})?)\s+квадрат/i));
  addMaxArea(pick(/\sне\s+более\s+(\d{1,3}(?:[.,]\d{1,2})?)\s+квадрат/i));
  addMinArea(pick(new RegExp(`\\sот\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)\\s+${AREA_TAIL}`, 'i')));
  addMaxArea(pick(new RegExp(`\\sдо\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)\\s+${AREA_TAIL}`, 'i')));
  addMinArea(pick(/\sплощад(?:ь|и|ью|ей)\s+от\s+(\d{1,3}(?:[.,]\d{1,2})?)(?=\s|$)/i));
  addMaxArea(pick(/\sплощад(?:ь|и|ью|ей)\s+до\s+(\d{1,3}(?:[.,]\d{1,2})?)(?=\s|$)/i));

  if (min_area == null && max_area == null) {
    const okolo = pick(
      new RegExp(
        `(?:общ(?:ей|ая)?\\s+)?площад(?:ь|и|ью|ей)\\s+около\\s+(\\d{1,3}(?:[.,]\\d{1,2})?)(?:\\s+${AREA_TAIL})?`,
        'i'
      )
    );
    if (okolo != null) {
      areaApprox = true;
      const d = Math.max(5, Math.round(okolo * 0.12));
      min_area = Math.max(10, okolo - d);
      max_area = okolo + d;
    } else {
      const exactA = pick(
        new RegExp(
          `(?:общ(?:ей|ая)?\\s+)?площад(?:ь|и|ью|ей)\\s*(?:~|≈)?\\s*(\\d{1,3}(?:[.,]\\d{1,2})?)(?:\\s+${AREA_TAIL})?`,
          'i'
        )
      );
      if (exactA != null) {
        min_area = exactA;
        max_area = exactA;
      }
    }
  }

  if (min_area == null && max_area == null) {
    addMinArea(pick(/\s(\d{1,3}(?:[.,]\d{1,2})?)\s+метр(?:ов|а)?\s+квадрат/i));
    addMaxArea(pick(/\sдо\s+(\d{1,3}(?:[.,]\d{1,2})?)\s+метр(?:ов|а)?\s+квадрат/i));
  }
  if (min_area == null && max_area == null) {
    addMinArea(pick(/\s(\d{1,3}(?:[.,]\d{1,2})?)\s+квадрат(?:ов|а|ные|ных)?(?=\s|$)/i));
    addMinArea(pick(/\s(\d{1,3}(?:[.,]\d{1,2})?)\s+кв\.?\s*м/i));
  }
}

if (min_area == null || max_area == null) {
  for (const m of t.matchAll(/\sот\s+(\d{2,3})\s+до\s+(\d{2,3})/gi)) {
    const end = m.index + m[0].length;
    const after = t.slice(end, end + 20);
    if (/^\s*(млн|миллион|тыс|руб|₽)/i.test(after)) continue;
    if (
      /^\s*(?:кв|м(?:²|2)|м\.|квадрат)/i.test(after) ||
      /^\s*$/.test(after) ||
      /^\s*[,.;]/.test(after)
    ) {
      const a = num(m[1]);
      const b = num(m[2]);
      if (a == null || b == null) continue;
      const lo = Math.min(a, b);
      const hi = Math.max(a, b);
      if (lo >= 15 && hi <= 320 && hi - lo >= 3) {
        min_area = lo;
        max_area = hi;
        break;
      }
    }
  }
}

const roomWordMap = {
  одна: 1,
  одну: 1,
  одной: 1,
  один: 1,
  два: 2,
  две: 2,
  двух: 2,
  двумя: 2,
  три: 3,
  трех: 3,
  тремя: 3,
  трёх: 3,
  четыре: 4,
  четырех: 4,
  четырёх: 4,
  четырьмя: 4,
  пять: 5,
  пяти: 5,
  пятью: 5,
  шесть: 6,
  шести: 6,
  шестью: 6,
};

let rooms = [];

for (const m of t.matchAll(/\s([1-6])\s*[-–]?\s*(к\.?|комнатн|комн\.?)(?=\s|$)/gi)) {
  rooms.push(Number(m[1]));
}
for (const m of t.matchAll(/\s([1-6])\s*х\s*комнат/gi)) rooms.push(Number(m[1]));
for (const m of t.matchAll(/\s([1-6])\s*[-–]?\s*х\s*комнатн/gi)) {
  rooms.push(Number(m[1]));
}
for (const m of t.matchAll(
  /\s([1-6])\s+комнат(?:ы|у|а|ной|ную|ами|ах)?(?=\s|$)/gi
)) {
  rooms.push(Number(m[1]));
}
for (const m of t.matchAll(
  /\s([1-6])\s*[-–]?\s*комнатная(?:я|ю|ой|ые)?\s+квартир/gi
)) {
  rooms.push(Number(m[1]));
}

const rw =
  'одна|одну|одной|один|два|две|двух|двумя|три|трех|трёх|тремя|четыре|четырех|четырёх|четырьмя|пять|пяти|пятью|шесть|шести|шестью';
for (const m of t.matchAll(new RegExp(`\\s(${rw})\\s+комнат`, 'gi'))) {
  const k = m[1].toLowerCase();
  if (roomWordMap[k] != null) rooms.push(roomWordMap[k]);
}

if (/студи|студенческ/.test(t)) rooms.push(0);
if (/однушк|однокомн|однокомнатн|\s1\s*комнатн/.test(t)) rooms.push(1);
if (/двушк|двухкомн|двухкомнатн|\s2\s*комнатн/.test(t)) rooms.push(2);
if (/трешк|трёшк|трехкомн|трёхкомн|трёхкомнатн|трехкомнатн|\s3\s*комнатн/.test(t)) {
  rooms.push(3);
}
if (/четырёхкомн|четырехкомн|четырёшк|четырёхкомнатн|\s4\s*комнатн/.test(t)) {
  rooms.push(4);
}
for (const m of t.matchAll(/\s([1-6])\s*[- ]?(к|комн|комнат)(?=\s|$)/gi)) {
  rooms.push(Number(m[1]));
}

rooms = [...new Set(rooms)].filter((r) => r >= 0 && r <= 6);

let floor_min = null;
let floor_max = null;

let floorRange =
  t.match(/\sэтаж\s+с\s+(\d{1,2})\s+по\s+(\d{1,2})(?=\s|$)/i) ||
  t.match(/\sс\s+(\d{1,2})\s+по\s+(\d{1,2})\s+этаж/i) ||
  t.match(/\sот\s+(\d{1,2})\s+до\s+(\d{1,2})\s+этажа?/i);

if (floorRange) {
  floor_min = Number(floorRange[1]);
  floor_max = Number(floorRange[2]);
} else {
  const naEt =
    t.match(/\sна\s+(\d{1,2})\s+этаже?(?=\s|$)/i) ||
    t.match(/\s(\d{1,2})\s*[-–]?(й|ом|ого)\s+этаже?(?=\s|$)/i) ||
    t.match(/\sэтаж\s*(?:номер\s*)?(\d{1,2})(?=\s|$)/i) ||
    t.match(/\s(\d{1,2})\s+этаж(?:е|а)?(?=\s|$)/i);
  if (naEt) {
    const fl = Number(naEt[1]);
    floor_min = fl;
    floor_max = fl;
  }
}

if (floor_min == null) {
  const a =
    pick(/\sэтаж\s+от\s+(\d{1,2})(?=\s|$)/i) ??
    pick(/\sот\s+(\d{1,2})(?:[-–]?(?:го|й))?\s+этажа/i) ??
    pick(/\sс\s+(\d{1,2})(?:[-–]?(?:го|й))?\s+этажа/i) ??
    pick(/\sне\s+ниже\s+(\d{1,2})(?:[-–]?(?:го|й))?\s+этажа/i);
  if (a != null) floor_min = a;
}

if (floor_max == null) {
  const b =
    pick(/\sэтаж\s+до\s+(\d{1,2})(?=\s|$)/i) ??
    pick(/\sдо\s+(\d{1,2})(?:[-–]?(?:го|й))?\s+этажа/i) ??
    pick(/\sне\s+выше\s+(\d{1,2})(?:[-–]?(?:го|й))?\s+этажа/i);
  if (b != null) floor_max = b;
}

const price_min = parsePriceMin(t);
const price_max = parsePriceMax(t);

const not_first = /не\s*первый|не\s*1[- ]й|выше\s*первого/.test(t);
const not_last = /не\s*последний|не\s*верхн/.test(t);

const districtDefs = [
  ['ленинск', 'ленинский'],
  ['октябр', 'октябрьский'],
  ['пролетарск', 'пролетарский'],
  ['светотех', 'светотехстрой'],
  ['химмаш', 'химмаш'],
  ['луховк', 'луховка'],
  ['ялг', 'ялга'],
  ['юго-запад', 'юго-запад'],
  ['юго запад', 'юго-запад'],
  ['центр', 'центр'],
  ['центральн', 'центр'],
];
const districts = [];
for (const [needle, token] of districtDefs) {
  if (t.includes(needle)) districts.push(token);
}
const districtsUniq = [...new Set(districts)];

// POI requirements (ветка "рядом должно быть ...")
const poi_required = [];

// ВАЖНО:   в JS не работает с кириллицей, поэтому используем unicode-safe границы слова
function hasWord(re) {
  try { return re.test(t); } catch { return false; }
}
const W = (s) => new RegExp(`(^|[^\p{L}])${s}([^\p{L}]|$)`, 'iu');

if (hasWord(W('аптек[а-я]*'))) poi_required.push('pharmacy');
if (hasWord(W('школ[а-я]*'))) poi_required.push('school');
// детский сад / детсад / садик / д/с
if (hasWord(W('детск[а-я]*\\s*сад[а-я]*')) || hasWord(W('детсад[а-я]*')) || hasWord(W('садик[а-я]*')) || hasWord(W('д\\s*/\\s*с'))) {
  poi_required.push('kindergarten');
}
// продукты / магазин / супермаркет / пятерочка / магнит
if (hasWord(W('продукт[а-я]*')) || hasWord(W('магазин[а-я]*')) || hasWord(W('супермаркет[а-я]*')) || hasWord(W('пятерочк[а-я]*')) || hasWord(W('магнит[а-я]*'))) {
  poi_required.push('grocery');
}

const poi_required_uniq = [...new Set(poi_required)];


const streetHints = [];
function pushStreetVariants(word) {
  if (!word || word.length < 3) return;
  const low = String(word).toLowerCase().replace(/ё/g, 'е');
  streetHints.push(low);
  if (low.length > 5 && /(ой|ая|ую|ее)$/.test(low)) streetHints.push(low.slice(0, -2));
  if (low.length > 4 && /[аеиоуыэюя]$/.test(low)) streetHints.push(low.slice(0, -1));
}
const sm = t.match(/улиц[аеыу]\s+([а-яё\-]+)/i);
if (sm) pushStreetVariants(sm[1]);
const ulm = t.match(/\bul\.?\s*([а-яё\d\-]+)/i);
if (ulm) pushStreetVariants(ulm[1]);
const pr = t.match(/\sпр\.?\s*([а-яё\d\-]+)/i);
if (pr) pushStreetVariants(pr[1]);

const naStreet = t.match(/\sна\s+([а-яё\-]{4,})(?=\s|[,.]|$)/i);
if (naStreet && !/^этаж/i.test(naStreet[1])) {
  pushStreetVariants(naStreet[1]);
}

return [
  {
    json: {
      chat_id: x.chat_id,
      user_text: x.user_text,
      filters: {
        rooms,
        price_min,
        price_max,
        min_area,
        max_area,
        area_approx: areaApprox,
        floor_min,
        floor_max,
        districts: districtsUniq,
        not_first,
        not_last,
        streetHints: [...new Set(streetHints)],
        poi_required: poi_required_uniq,
      },
    },
  },
];

// Берём исходный item из предыдущего узла (Filter Dataset) по индексу
const src = $items('Filter Dataset', 0)[$itemIndex]?.json ?? {};
const resp = $json;

function getPos(o) {
  try {
    const fm = o?.response?.GeoObjectCollection?.featureMember;
    const pos = fm?.[0]?.GeoObject?.Point?.pos;
    if (!pos) return null;
    const [lon, lat] = String(pos).split(' ').map(Number);
    if (!Number.isFinite(lon) || !Number.isFinite(lat)) return null;
    return { lon, lat };
  } catch { return null; }
}

const pos = getPos(resp);
const out = { ...src };
if (pos) {
  out.geo = { lon: pos.lon, lat: pos.lat };
} else {
  out.geo = null;
  out.geo_error = 'geocode_failed';
}
return { json: out };

