={{ JSON.stringify({
  model: 'gpt-4.1',
  temperature: 0.5,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content:
        'Ты аналитик объявлений о продаже квартир. Верни ТОЛЬКО валидный JSON-объект (без Markdown/пояснений). ' +
        'НЕЛЬЗЯ выдумывать факты — используй только то, что в ФАКТАХ. ' +
        'verdict_ppsm и verdict_overall строго ASCII: good|ok|bad|sus. ' +
        'pros/cons/flags/one_liner — строго на русском. ' +
        'Пиши живо, как опытный риелтор-аналитик: не канцелярит, а польза для покупателя. ' +
        'Не пересказывай вход (типа "квартира в районе") — пиши выводы/последствия. ' +
        'Работай как инспектор: отмечай только наблюдаемые факты, а не отсутствие несуществующих полей. ' +
        'Минусы пиши только по фактам из объявления; если фактических минусов нет, cons должен быть пустым массивом. ' +
        'Запрещено писать "нет соседей сверху", если последний этаж = нет.'
    },
    {
      role: 'user',
      content: (() => {
        const price = Number($json.price_rub);
        const area = Number($json.area_m2);
        const rooms = Number($json.rooms);
        const ppsm = (Number.isFinite(price) && Number.isFinite(area) && area > 0)
          ? Math.round(price / area)
          : null;

        const floor = Number($json.floor);
        const total = Number($json.floor_total);
        const isLast = Number.isFinite(floor) && Number.isFinite(total) && total > 0 && floor === total;
        const isFirst = Number.isFinite(floor) && floor === 1;
        const hasAddress = String($json.address ?? '').trim().length > 0;
        const areaNum = Number.isFinite(area) ? area : null;
        const roomNum = Number.isFinite(rooms) ? rooms : null;

        function ppsmVerdict(value) {
          if (!Number.isFinite(value)) return 'sus';
          if (value <= 85000) return 'good';
          if (value <= 110000) return 'ok';
          if (value <= 130000) return 'bad';
          return 'sus';
        }

        function areaProfile(roomCount, areaValue) {
          if (!Number.isFinite(areaValue) || areaValue <= 0 || !Number.isFinite(roomCount)) {
            return { level: 'unknown', text: 'площадь не оценена', severity: 0 };
          }
          if (areaValue < 14) {
            return { level: 'critical', text: 'критически маленькая площадь для отдельного жилья', severity: 3 };
          }
          if (roomCount <= 0) {
            if (areaValue < 18) return { level: 'very_small', text: 'очень маленькая студия', severity: 2 };
            if (areaValue < 22) return { level: 'compact', text: 'компактная студия', severity: 1 };
            if (areaValue <= 35) return { level: 'normal', text: 'нормальная студия', severity: 0 };
            return { level: 'spacious', text: 'просторная студия', severity: 0 };
          }
          const minOk = roomCount === 1 ? 28 : roomCount === 2 ? 42 : roomCount === 3 ? 58 : 72;
          const verySmall = roomCount === 1 ? 18 : roomCount === 2 ? 35 : roomCount === 3 ? 50 : 60;
          const spacious = roomCount === 1 ? 45 : roomCount === 2 ? 65 : roomCount === 3 ? 85 : 95;
          if (areaValue < verySmall) return { level: 'very_small', text: `очень маленькая для ${roomCount}-комнатной квартиры`, severity: 2 };
          if (areaValue < minOk) return { level: 'compact', text: `компактная для ${roomCount}-комнатной квартиры`, severity: 1 };
          if (areaValue <= spacious) return { level: 'normal', text: `нормальная для ${roomCount}-комнатной квартиры`, severity: 0 };
          return { level: 'spacious', text: `просторная для ${roomCount}-комнатной квартиры`, severity: 0 };
        }

        function verdictFromScore(score) {
          if (score >= 75) return 'good';
          if (score >= 55) return 'ok';
          if (score >= 35) return 'bad';
          return 'sus';
        }

        function notBetterThan(base, verdict) {
          const order = ['good', 'ok', 'bad', 'sus'];
          return order[Math.max(order.indexOf(base), order.indexOf(verdict))];
        }

        function targetScore(ppsmValue, areaInfo, floorValue, totalValue) {
          const baseVerdict = ppsmVerdict(ppsmValue);
          let score = baseVerdict === 'good' ? 84 : baseVerdict === 'ok' ? 70 : baseVerdict === 'bad' ? 50 : 30;
          if (areaInfo.level === 'critical') score -= 32;
          else if (areaInfo.level === 'very_small') score -= 20;
          else if (areaInfo.level === 'compact') score -= 6;
          if (Number.isFinite(floorValue) && floorValue === 1) score -= 10;
          if (Number.isFinite(floorValue) && Number.isFinite(totalValue) && totalValue > 0 && floorValue === totalValue) {
            score -= totalValue <= 5 ? 7 : 5;
          }
          if (!Number.isFinite(floorValue) || !Number.isFinite(totalValue)) score -= 6;
          return Math.max(10, Math.min(95, Math.round(score)));
        }

        const areaInfo = areaProfile(roomNum, area);
        const requiredPpsmVerdict = ppsmVerdict(ppsm);
        const requiredScore = targetScore(ppsm, areaInfo, floor, total);
        const requiredOverallVerdict = notBetterThan(requiredPpsmVerdict, verdictFromScore(requiredScore));
        const styleAngles = [
          'практичность для жизни',
          'ликвидность при перепродаже',
          'семейный сценарий',
          'комфорт этажа',
          'баланс цены и площади',
          'пространство и зонирование',
        ];
        const styleSeed = [
          Number.isFinite(roomNum) ? roomNum : 0,
          Number.isFinite(area) ? Math.round(area) : 0,
          Number.isFinite(floor) ? floor : 0,
          Number.isFinite(total) ? total : 0,
          Number.isFinite(price) ? Math.round(price / 100000) : 0,
        ].reduce((sum, n) => sum + n, 0);
        const styleAngle = styleAngles[Math.abs(styleSeed) % styleAngles.length];

        return `ФАКТЫ (только они):
комнат: ${$json.rooms ?? ''}
площадь_м2: ${$json.area_m2 ?? ''}
класс_площади: ${areaInfo.level}
оценка_площади: ${areaInfo.text}
этаж: ${$json.floor ?? ''}
этажность: ${$json.floor_total ?? ''}
первый_этаж: ${isFirst ? 'да' : 'нет'}
