обязательный_score_overall: ${requiredScore}
адрес_есть: ${hasAddress ? 'да' : 'нет'}\npoi_pharmacy_count: ${$json.poi?.pharmacy?.count ?? ''}\npoi_pharmacy_min_m: ${$json.poi?.pharmacy?.min_distance_m ?? ''}\npoi_school_count: ${$json.poi?.school?.count ?? ''}\npoi_school_min_m: ${$json.poi?.school?.min_distance_m ?? ''}\npoi_kindergarten_count: ${$json.poi?.kindergarten?.count ?? ''}\npoi_kindergarten_min_m: ${$json.poi?.kindergarten?.min_distance_m ?? ''}\npoi_grocery_count: ${$json.poi?.grocery?.count ?? ''}\npoi_grocery_min_m: ${$json.poi?.grocery?.min_distance_m ?? ''}
