{
  "verdict_ppsm": "good"|"ok"|"bad"|"sus",
  "verdict_overall": "good"|"ok"|"bad"|"sus",
  "score_overall": 0-100,
  "pros": ["..."],
  "cons": ["..."],
  "flags": ["..."],
