const resp = $json;
const content = resp?.choices?.[0]?.message?.content ?? '';
let parsed = {};
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { verdict: '—', score: null, flags: ['bad_json'], one_liner: String(content).slice(0, 400) };
}

// ВАЖНО: берём исходный item с POI (после Filter By POI), иначе потеряем poi/geo
let src = {};
try {
  const it = $items('Filter By POI', 0)[$itemIndex];
  if (it && it.json && typeof it.json === 'object' && !Array.isArray(it.json)) {
    src = it.json;
  }
} catch (e) {}

if (!src || typeof src !== 'object' || Array.isArray(src)) src = {};
const out = { ...src, ai: parsed };
return { json: out };

const items = $input.all().map(i => i.json);
const first = items[0] || {};
const chat_id = first.chat_id;
if (first.no_results) return [{ json: { chat_id, text: first.text } }];

function fmt(v){ return v == null ? '—' : Number(v).toLocaleString('ru-RU'); }
function floorText(f,t){
  if (f == null && t == null) return '—';
  if (f != null && t != null) return `${f}/${t} эт.`;
  return String(f ?? t) + ' эт.';
}

const verdictRu = { good: 'выгодно', ok: 'норм', bad: 'дорого', sus: 'сомнительно' };

function takeStrings(v, max){
  if (!Array.isArray(v)) return [];
  return v
    .filter(s => typeof s === 'string' && s.trim())
    .map(s => s.trim())
    .slice(0, max);
}

function areaLevel(x){
  const area = Number(x.area_m2);
  const rooms = Number(x.rooms);
  if (!Number.isFinite(area) || area <= 0 || !Number.isFinite(rooms)) return 'unknown';
  if (area < 14) return 'critical';
  if (rooms <= 0) {
    if (area < 18) return 'very_small';
    if (area < 22) return 'compact';
    if (area <= 35) return 'normal';
    return 'spacious';
  }
  const minOk = rooms === 1 ? 28 : rooms === 2 ? 42 : rooms === 3 ? 58 : 72;
  const verySmall = rooms === 1 ? 18 : rooms === 2 ? 35 : rooms === 3 ? 50 : 60;
  const spacious = rooms === 1 ? 45 : rooms === 2 ? 65 : rooms === 3 ? 85 : 95;
  if (area < verySmall) return 'very_small';
  if (area < minOk) return 'compact';
  if (area <= spacious) return 'normal';
  return 'spacious';
}

function hasMissingInfoText(s){
  return /нет\s+(данных|информации|сведений)|не\s*указ|неизвест|ремонт|состояни[ея]\s+(дом|квартир)|инфраструктур|парковк|транспорт/i.test(String(s || ''));
}

function hasWrongAreaComplaint(s, x){
  const level = areaLevel(x);
  if (level !== 'normal' && level !== 'spacious') return false;
  const text = String(s || '').toLowerCase();
  return /(площад|м²|м2)/i.test(text) && /(компакт|маленьк|мало|тесн|недостат)/i.test(text);
}

function hasWrongAreaPraise(s, x){
  const level = areaLevel(x);
  if (level !== 'critical' && level !== 'very_small') return false;
  const text = String(s || '').toLowerCase();
  return /(площад|м²|м2)/i.test(text) && /(подход|нормаль|достаточ|комфорт|хорош|плюс)/i.test(text);
}

function takeProsStrings(v, x, max){
  return takeStrings(v, max)
    .filter(s => !hasMissingInfoText(s))
    .filter(s => !hasWrongAreaPraise(s, x))
    .filter(s => !hasWrongAreaComplaint(s, x))
    .slice(0, max);
}

function takeConsStrings(v, x, max){
  return takeStrings(v, max)
    .filter(s => !hasMissingInfoText(s))
    .filter(s => !hasWrongAreaComplaint(s, x))
    .slice(0, max);
}

function factFlags(v, x, max){
  const price = Number(x.price_rub);
  const area = Number(x.area_m2);
  const ppsm = Number.isFinite(price) && Number.isFinite(area) && area > 0 ? Math.round(price / area) : null;
  const floor = Number(x.floor);
  const total = Number(x.floor_total);
  const level = areaLevel(x);

  return takeStrings(v, max).filter(flag => {
    if (hasMissingInfoText(flag)) return false;
    const f = flag.toLowerCase();
    if (f.includes('ниже рынка')) return false;
    if (f.includes('выше рынка')) return ppsm != null && ppsm > 110000;
    if (f.includes('первый этаж')) return Number.isFinite(floor) && floor === 1;
    if (f.includes('последний этаж')) return Number.isFinite(floor) && Number.isFinite(total) && total > 0 && floor === total;
    if (f.includes('критически') && f.includes('площад')) return level === 'critical';
    if (f.includes('очень малень') && f.includes('площад')) return level === 'very_small';
    if (f.includes('компакт') && f.includes('площад')) return level === 'compact';
    if (f.includes('малень') && f.includes('площад')) return level === 'critical' || level === 'very_small' || level === 'compact';
    if (f.includes('адрес')) return !x.address;
    if (f.includes('этажность')) return x.floor == null || x.floor_total == null;
    return true;
  }).slice(0, max);
}

// цена/м² + флаги риска (быстрый хард-скоринг, как запасной план)
function analyze(x){
  const price = Number(x.price_rub);
  const area = Number(x.area_m2);
  const hasNum = Number.isFinite(price) && Number.isFinite(area) && area > 0;
  const ppsm = hasNum ? Math.round(price / area) : null;

  let label = '—';
  if (ppsm != null) {
    if (ppsm <= 85000) label = 'выгодно';
    else if (ppsm <= 110000) label = 'норм';
    else label = 'дорого';
  }

  const flags = [];
  if (!x.address) flags.push('нет адреса');
  const level = areaLevel(x);
  if (level === 'critical') flags.push('критически маленькая площадь');
  else if (level === 'very_small') flags.push('очень маленькая площадь');
  if (price && price < 500000) flags.push('подозрительно низкая цена');
  if (price && price > 25000000) flags.push('очень высокая цена');

  return { ppsm, label, flags };
}

const lines = [];
items.forEach((x, i) => {
  const roomLabel = x.rooms === 0 ? 'Студия' : (x.rooms != null ? `${x.rooms}-комн.` : '—');
  const a = analyze(x);

  const ai = x.ai || {};
  const rawVerdict = ai.verdict_overall ?? ai.verdict ?? ai.verdict_ppsm;
  const v = typeof rawVerdict === 'string' ? rawVerdict.trim() : '';
  const vru = verdictRu[v] || v || '—';
  const rawScore = ai.score_overall ?? ai.score;
  const score = (rawScore != null && Number.isFinite(Number(rawScore))) ? Math.round(Number(rawScore)) : null;
  const pros = takeProsStrings(ai.pros, x, 5);
  const cons = takeConsStrings(ai.cons, x, 5);
  const aiFlags = factFlags(ai.flags, x, 5);
  const oneLiner = hasMissingInfoText(ai.one_liner) ? '' : String(ai.one_liner || '').trim();

  lines.push(`${i+1}. ${roomLabel}, ${x.area_m2 ?? '—'} м², ${floorText(x.floor, x.floor_total)}`);
  lines.push(`📍 ${x.address || '—'} (${x.district || '—'})`);
  lines.push(`💰 ${fmt(x.price_rub)} ₽`);

  const p = x.poi || {};
  const req = Array.isArray(x.poi_required) ? x.poi_required : [];
  // Если пользователь не просил POI — не выводим строку "Рядом", чтобы не шуметь.
  const wanted = req.length ? req : [];

  function poiTxt(label, obj){
    if (!obj) return null;
    const c = obj.count;
    const d = obj.min_distance_m;
    if (c == null && d == null) return null;
    const cText = (c == null) ? '—' : String(c);
    const dText = (d == null) ? '—' : (String(d) + ' м');
    return `${label}: ${cText}, ближ. ${dText}`;
  }

  const labelMap = {
    pharmacy: 'Аптеки',
    school: 'Школы',
    kindergarten: 'Сады',
    grocery: 'Продукты',
  };

  const poiParts = wanted
    .map((k) => poiTxt(labelMap[k] || k, p?.[k]))
    .filter(Boolean);

  if (poiParts.length) {
    lines.push('🏪 Рядом (≤~1км): ' + poiParts.join(' | '));
  }



  if (vru !== '—' || score != null || pros.length || cons.length || aiFlags.length || oneLiner) {
    const aiParts = [];
    if (vru !== '—') aiParts.push(`${vru}${score != null ? ` (${score}/100)` : ''}`);
    else if (score != null) aiParts.push(`${score}/100`);
    if (oneLiner) aiParts.push(oneLiner);
    if (aiParts.length) lines.push(`🤖 GPT: ${aiParts.join(' — ')}`);
    if (pros.length) lines.push(`✅ Плюсы: ${pros.join('; ')}`);
    if (cons.length) lines.push(`⚠️ Минусы: ${cons.join('; ')}`);
    if (aiFlags.length) lines.push(`🚩 Риски: ${aiFlags.join('; ')}`);
  }

  lines.push(`📊 Цена/м²: ${a.label}${a.ppsm != null ? ` (≈${fmt(a.ppsm)} ₽/м²)` : ''}${a.flags.length ? `; ⚠️ ${a.flags.join(', ')}` : ''}`);
  lines.push(`🔗 ${x.url}`);
  lines.push('');
});

const header = `🏠 Нашёл ${items.length} вариант(ов) по вашему запросу:\n\n`;
const body = lines.join('\n');
const MAX = 3900;

function splitTelegramChunks(prefix, rest) {
  const chunks = [];
  let full = prefix + rest;
  while (full.length > 0) {
    if (full.length <= MAX) {
      chunks.push(full);
      break;
    }
    let cut = full.lastIndexOf('\n', MAX);
    if (cut < MAX * 0.4) cut = MAX;
    chunks.push(full.slice(0, cut));
    full = full.slice(cut).replace(/^\n+/, '');
  }
  return chunks;
}

const parts = splitTelegramChunks(header, body);
return parts.map((text, idx) => ({
  json: {
    chat_id,
    text: parts.length > 1 ? `Часть ${idx + 1}/${parts.length}\n${text}` : text,
  },
}));

