const src = $items('Parse Coords', 0)[$itemIndex]?.json ?? {};
const resp = $json;

function haversineMeters(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const toRad = (d) => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1))*Math.cos(toRad(lat2))*Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

function emptyStats() {
  return { count: 0, min_distance_m: null };
}

function coordsOf(el) {
  if (!el) return null;
  if (el.type === 'node') {
    const lat = Number(el.lat);
    const lon = Number(el.lon);
    if (Number.isFinite(lat) && Number.isFinite(lon)) return { lat, lon };
    return null;
  }
  const c = el.center;
  if (c) {
    const lat = Number(c.lat);
    const lon = Number(c.lon);
    if (Number.isFinite(lat) && Number.isFinite(lon)) return { lat, lon };
  }
  return null;
}

function categoryOf(tags) {
  if (!tags) return null;
  const amenity = tags.amenity;
  if (amenity === 'pharmacy') return 'pharmacy';
  if (amenity === 'school') return 'school';
  if (amenity === 'kindergarten') return 'kindergarten';
  const shop = tags.shop;
  if (shop === 'supermarket' || shop === 'convenience' || shop === 'grocery') return 'grocery';
  return null;
}

function compute(elements, center) {
  const out = {
    pharmacy: emptyStats(),
    school: emptyStats(),
    kindergarten: emptyStats(),
    grocery: emptyStats(),
  };

  if (!center || !Number.isFinite(center.lat) || !Number.isFinite(center.lon)) return out;
  const els = Array.isArray(elements) ? elements : [];

  for (const el of els) {
    const cat = categoryOf(el?.tags);
    if (!cat) continue;
    const p = coordsOf(el);
    if (!p) continue;
    const d = haversineMeters(center.lat, center.lon, p.lat, p.lon);
    if (!Number.isFinite(d)) continue;

    out[cat].count += 1;
    if (out[cat].min_distance_m == null || d < out[cat].min_distance_m) {
      out[cat].min_distance_m = d;
    }
  }

  for (const k of Object.keys(out)) {
    out[k].min_distance_m = out[k].min_distance_m == null ? null : Math.round(out[k].min_distance_m);
  }
  return out;
}

const center = src.geo;
const stats = compute(resp?.elements, center);
const out = { ...src };
out.poi = stats;
return { json: out };

const items = $input.all().map(i => i.json);
if (!items.length) return [];

const first = items[0] || {};
const chat_id = first.chat_id;
const required = Array.isArray(first.poi_required) ? first.poi_required : [];

if (!required.length) return items.map(x => ({ json: x }));

const RADIUS_M = 1000;

function okCat(x, cat) {
  const s = x?.poi?.[cat];
  if (!s) return false;
  const c = Number(s.count);
  const d = s.min_distance_m == null ? null : Number(s.min_distance_m);
  if (!Number.isFinite(c) || c <= 0) return false;
  if (d == null) return true;
  if (!Number.isFinite(d)) return false;
  return d <= RADIUS_M;
}

const kept = items.filter(x => required.every(cat => okCat(x, cat)));

if (!kept.length) {
  const reqRu = {
    pharmacy: 'аптека',
    school: 'школа',
    kindergarten: 'детский сад',
    grocery: 'продуктовый магазин',
  };
  const nice = required.map(k => reqRu[k] || k).join(', ');
  return [{
    json: {
